import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCampaigns } from '@/hooks/useCampaigns';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Checkbox } from "@/components/ui/checkbox";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Megaphone,
    Search,
    Filter,
    Play,
    Pause,
    MoreHorizontal,
    Loader2,
    Eye,
    TrendingUp,
    ListChecks,
    X,
    ChevronLeft,
    ChevronRight,
    ArrowUpRight,
    Zap,
    Sparkles,
    ShieldCheck,
    Briefcase,
    Activity,
    Target,
    BarChart3,
    MousePointerClick,
    RefreshCw
} from 'lucide-react';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { toast } from 'sonner';
import { useQueryClient } from '@tanstack/react-query';
import { TagList } from '@/components/tags/TagBadge';
import { TagSelector } from '@/components/tags/TagSelector';
import { motion, AnimatePresence } from 'framer-motion';

const PAGE_SIZE = 12;

const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
    }).format(value);
};

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(1)}K`;
    return value.toLocaleString('pt-BR');
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function Campanhas() {
    const navigate = useNavigate();
    const queryClient = useQueryClient();
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [page, setPage] = useState(0);
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [isBulkProcessing, setIsBulkProcessing] = useState(false);

    // AI Diagnosis State
    const [isAiModalOpen, setIsAiModalOpen] = useState(false);
    const [isAiLoading, setIsAiLoading] = useState(false);
    const [selectedCampaignId, setSelectedCampaignId] = useState<string | null>(null);
    const [aiData, setAiData] = useState<any>(null);

    const handleRunDiagnosis = async (id: string) => {
        setSelectedCampaignId(id);
        setIsAiModalOpen(true);
        setIsAiLoading(true);
        setAiData(null);

        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/audit-campaign`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ campaign_id: id }),
            });

            if (!response.ok) throw new Error('Falha na análise');
            const data = await response.json();
            setAiData(data);
        } catch (error) {
            console.error(error);
            toast.error('Erro ao executar diagnóstico IA');
            setIsAiModalOpen(false);
        } finally {
            setIsAiLoading(false);
        }
    };

    const { data, isLoading } = useCampaigns({
        search: search || undefined,
        status: statusFilter !== 'all' ? statusFilter : undefined,
        limit: PAGE_SIZE,
        offset: page * PAGE_SIZE,
    });

    const campaigns = data?.campaigns || [];
    const total = data?.total || 0;
    const totalPages = Math.ceil(total / PAGE_SIZE);

    const getStatusState = (status: string) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            active: { label: 'Em Operação', color: 'emerald-500', icon: Play },
            paused: { label: 'Em Espera', color: 'amber-500', icon: Pause },
            deleted: { label: 'Removida', color: 'rose-500', icon: X },
            archived: { label: 'Legado', color: 'ch-text-dimmed', icon: RefreshCw },
        };
        return config[status] || config.paused;
    };

    const handleViewCampaign = (campaignId: string) => {
        navigate(`/campanhas/${campaignId}`);
    };

    const toggleSelectAll = () => {
        if (selectedIds.length === campaigns.length && campaigns.length > 0) {
            setSelectedIds([]);
        } else {
            setSelectedIds(campaigns.map(c => c.id));
        }
    };

    const toggleSelect = (id: string, checked: boolean) => {
        if (checked) {
            setSelectedIds(prev => [...prev, id]);
        } else {
            setSelectedIds(prev => prev.filter(i => i !== id));
        }
    };

    const executeAction = async (campaignId: string, action: string) => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) throw new Error('No session');

        const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/meta-campaign-action`, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${session.access_token}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                campaign_id: campaignId,
                action,
            }),
        });

        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error || 'Failed to perform action');
        }
        return response.json();
    };

    const handleBulkAction = async (action: 'pause' | 'activate') => {
        if (selectedIds.length === 0) return;
        setIsBulkProcessing(true);
        let successCount = 0;
        let errorCount = 0;

        try {
            const promises = selectedIds.map(id =>
                executeAction(id, action)
                    .then(() => { successCount++; })
                    .catch(() => { errorCount++; })
            );

            await Promise.all(promises);

            if (successCount > 0) {
                toast.success(`${successCount} campanhas ${action === 'activate' ? 'ativadas' : 'pausadas'} com sucesso.`);
            }
            if (errorCount > 0) {
                toast.error(`Falha ao atualizar ${errorCount} campanhas.`);
            }

            setSelectedIds([]);
            queryClient.invalidateQueries({ queryKey: ['campaigns'] });

        } catch (error) {
            console.error(error);
            toast.error('Erro ao processar ação em massa.');
        } finally {
            setIsBulkProcessing(false);
        }
    };

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-10"
        >
            {/* Header Area */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-8">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <Megaphone className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-bold text-ch-orange uppercase tracking-wide">Operações Meta</span>
                    </div>
                    <h1 className="text-3xl font-bold text-ch-white tracking-tight uppercase">Gestor de Ecossistema</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Visão holística e orquestração de alto nível para suas campanhas.</p>
                </div>

                <div className="flex items-center gap-4">
                    <Button
                        onClick={() => navigate('/campanhas/nova')}
                        className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-14 px-8 shadow-xl group"
                    >
                        <Zap className="w-4 h-4 mr-2 group-hover:animate-pulse" />
                        Lançar Campanha
                    </Button>
                </div>
            </motion.div>

            {/* Performance Snapshot */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                    { label: 'Ecossistema', value: total, icon: BarChart3, color: 'ch-orange' },
                    { label: 'Performance', value: campaigns.filter(c => c.status === 'active').length, icon: Play, color: 'emerald-500' },
                    { label: 'Stand-by', value: campaigns.filter(c => c.status === 'paused').length, icon: Pause, color: 'amber-500' },
                    { label: 'Opex Total', value: formatCurrency(campaigns.reduce((acc, c) => acc + (c.spend || 0), 0)), icon: TrendingUp, color: 'blue-500' }
                ].map((stat) => (
                    <motion.div key={stat.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-[2rem] p-6 border-white/5 shadow-xl group">
                        <div className="flex items-center gap-4 mb-4">
                            <div className={`p-2.5 bg-${stat.color}/10 rounded-xl`}>
                                <stat.icon className={`w-5 h-5 text-${stat.color}`} />
                            </div>
                            <span className="text-[10px] font-bold text-ch-text-muted uppercase tracking-widest leading-none">{stat.label}</span>
                        </div>
                        <p className="text-2xl font-bold text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors">{stat.value}</p>
                    </motion.div>
                ))}
            </div>

            {/* Management & Filter Bar */}
            <motion.div variants={item} className="space-y-4">
                <AnimatePresence>
                    {selectedIds.length > 0 && (
                        <motion.div
                            initial={{ opacity: 0, scale: 0.98, y: 10 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.98, y: 10 }}
                            className="bg-ch-white text-ch-black rounded-3xl p-5 flex items-center justify-between shadow-2xl relative z-20"
                        >
                            <div className="flex items-center gap-5">
                                <div className="flex items-center justify-center w-12 h-12 rounded-2xl bg-ch-black text-ch-white font-black text-xl shadow-xl">
                                    {selectedIds.length}
                                </div>
                                <div>
                                    <p className="font-bold uppercase text-xs tracking-tight">Ativos em Fila</p>
                                    <p className="text-[10px] font-bold uppercase tracking-widest text-ch-black/40">Comandos de Lote Disponíveis</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <Button
                                    size="sm"
                                    className="bg-emerald-500 hover:bg-emerald-600 text-white font-black uppercase text-[10px] tracking-widest px-6 h-12 rounded-xl transition-all shadow-lg"
                                    onClick={() => handleBulkAction('activate')}
                                    disabled={isBulkProcessing}
                                >
                                    {isBulkProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                    Ativar Todos
                                </Button>
                                <Button
                                    size="sm"
                                    className="bg-amber-500 hover:bg-amber-600 text-white font-black uppercase text-[10px] tracking-widest px-6 h-12 rounded-xl transition-all shadow-lg"
                                    onClick={() => handleBulkAction('pause')}
                                    disabled={isBulkProcessing}
                                >
                                    {isBulkProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Pause className="w-4 h-4 mr-2" />}
                                    Pausar Todos
                                </Button>
                                <div className="h-8 w-px bg-ch-black/10 mx-2" />
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className="text-ch-black/40 hover:text-ch-black hover:bg-transparent"
                                    onClick={() => setSelectedIds([])}
                                    disabled={isBulkProcessing}
                                >
                                    <X className="w-6 h-6" />
                                </Button>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>

                <div className="flex flex-col md:flex-row items-center gap-4 bg-white/[0.02] border border-white/5 p-4 rounded-[1.5rem] backdrop-blur-sm">
                    <div className="relative flex-1 w-full">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                        <Input
                            placeholder="LOCALIZAR CAMPANHA POR NOME OU ID..."
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setPage(0);
                            }}
                            className="pl-12 bg-transparent border-none text-[10px] font-bold uppercase tracking-[.1em] focus-visible:ring-0 placeholder:opacity-20"
                        />
                    </div>
                    <div className="h-6 w-px bg-white/5 hidden md:block" />
                    <Select
                        value={statusFilter}
                        onValueChange={(v) => {
                            setStatusFilter(v);
                            setPage(0);
                        }}
                    >
                        <SelectTrigger className="w-full md:w-56 bg-ch-dark-gray/40 border-white/5 h-12 rounded-xl text-[10px] font-black uppercase tracking-widest">
                            <Filter className="w-4 h-4 mr-2 text-ch-orange" />
                            <SelectValue placeholder="Estado Meta" />
                        </SelectTrigger>
                        <SelectContent className="bg-ch-black-soft border-white/10 font-black uppercase text-[10px] tracking-widest">
                            <SelectItem value="all">Sincronizar Tudo</SelectItem>
                            <SelectItem value="active" className="text-emerald-500">Operantes</SelectItem>
                            <SelectItem value="paused" className="text-amber-500">Em Espera</SelectItem>
                            <SelectItem value="archived">Legado</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </motion.div>

            {/* Campaign Ledger */}
            <motion.div variants={item} className="glass rounded-[2rem] overflow-hidden border border-white/5 shadow-2xl transition-all">
                {isLoading ? (
                    <div className="p-32 flex flex-col items-center justify-center gap-6">
                        <div className="relative">
                            <RefreshCw className="w-16 h-16 animate-spin text-ch-orange opacity-20" />
                            <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-6 h-6 text-ch-orange" />
                        </div>
                        <div className="text-center">
                            <p className="text-[10px] font-black uppercase tracking-widest text-ch-orange mb-2">Sincronização de Dados</p>
                            <p className="text-ch-text-dimmed font-medium">Orquestrando dados através da API do Meta...</p>
                        </div>
                    </div>
                ) : campaigns.length > 0 ? (
                    <div className="overflow-x-auto">
                        <Table>
                            <TableHeader>
                                <TableRow className="border-white/5 hover:bg-transparent h-20 bg-white/[0.01]">
                                    <TableHead className="w-[80px] pl-8">
                                        <Checkbox
                                            className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:border-ch-orange rounded-md"
                                            checked={selectedIds.length === campaigns.length && campaigns.length > 0}
                                            onCheckedChange={toggleSelectAll}
                                        />
                                    </TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted">Ativo / Identidade</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted">Estado</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted">Objetivo de Targeting</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted text-right">Performance / Gasto</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted text-right">Budgeting</TableHead>
                                    <TableHead className="w-[100px] pr-8"></TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {campaigns.map((campaign) => {
                                    const state = getStatusState(campaign.status);
                                    const StateIcon = state.icon;
                                    return (
                                        <TableRow
                                            key={campaign.id}
                                            className="border-white/5 hover:bg-white/[0.02] cursor-pointer group transition-all h-24"
                                            onClick={() => handleViewCampaign(campaign.id)}
                                        >
                                            <TableCell className="pl-8" onClick={(e) => e.stopPropagation()}>
                                                <Checkbox
                                                    className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:border-ch-orange rounded-md"
                                                    checked={selectedIds.includes(campaign.id)}
                                                    onCheckedChange={(checked) => toggleSelect(campaign.id, checked as boolean)}
                                                />
                                            </TableCell>
                                            <TableCell>
                                                <div className="py-2">
                                                    <p className="font-bold text-ch-white group-hover:text-ch-orange transition-colors uppercase tracking-tight text-base">{campaign.name}</p>
                                                    <div className="flex items-center gap-3 mt-2">
                                                        <TagList tags={campaign.tags} />
                                                        <span className="text-[9px] font-bold text-ch-text-dimmed uppercase tracking-widest flex items-center gap-1.5 border-l border-white/10 pl-3">
                                                            <Activity className="w-3 h-3" /> Atualizado {formatDistanceToNow(new Date(campaign.updated_at), { addSuffix: true, locale: ptBR })}
                                                        </span>
                                                    </div>
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <span className={`text-[9px] font-bold uppercase tracking-[0.1em] px-3 py-1.5 rounded-full border bg-${state.color}/10 text-${state.color} border-${state.color}/20 flex items-center gap-2 w-fit`}>
                                                    <StateIcon className="w-3 h-3" />
                                                    {state.label}
                                                </span>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex items-center gap-2 text-[10px] font-bold text-ch-text-muted uppercase tracking-widest px-3 py-1.5 bg-white/5 rounded-xl border border-white/10 w-fit">
                                                    <Target className="w-3.5 h-3.5 text-ch-orange" />
                                                    {campaign.objective?.replace(/_/g, ' ') || 'ENGAJAMENTO'}
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex flex-col items-end gap-1.5">
                                                    <span className="text-base font-black text-ch-white tabular-nums">{formatCurrency(campaign.spend || 0)}</span>
                                                    <div className="flex items-center gap-3 text-[10px] font-bold text-ch-text-dimmed uppercase tracking-tighter">
                                                        <span className="flex items-center gap-1.5"><Eye className="w-3.5 h-3.5" /> {formatNumber(campaign.impressions || 0)}</span>
                                                        <span className="flex items-center gap-1.5"><MousePointerClick className="w-3.5 h-3.5" /> {formatNumber(campaign.clicks || 0)}</span>
                                                    </div>
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex flex-col items-end bg-white/[0.03] p-3 rounded-2xl border border-white/5 w-fit ml-auto">
                                                    <span className="text-sm font-black text-ch-white tabular-nums">{campaign.daily_budget ? formatCurrency(campaign.daily_budget) : 'FLEXÍVEL'}</span>
                                                    <span className="text-[9px] font-black text-ch-text-muted tracking-widest mt-1 uppercase">Alocação Diária</span>
                                                </div>
                                            </TableCell>
                                            <TableCell className="pr-8 text-right" onClick={(e) => e.stopPropagation()}>
                                                <div className="flex items-center justify-end gap-3">
                                                    <div onClick={(e) => e.stopPropagation()}>
                                                        <TagSelector
                                                            entityId={campaign.id}
                                                            entityType="campaign"
                                                            selectedTags={campaign.tags || []}
                                                        />
                                                    </div>
                                                    <DropdownMenu>
                                                        <DropdownMenuTrigger asChild>
                                                            <Button variant="ghost" size="icon" className="h-10 w-10 hover:bg-white/10 rounded-xl transition-all border border-transparent hover:border-white/5">
                                                                <MoreHorizontal className="w-5 h-5" />
                                                            </Button>
                                                        </DropdownMenuTrigger>
                                                        <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-56 p-2 shadow-2xl font-black uppercase text-[10px] tracking-[0.1em]">
                                                            <DropdownMenuItem onClick={() => handleViewCampaign(campaign.id)} className="rounded-lg py-3 hover:bg-white/5 cursor-pointer">
                                                                <Eye className="w-4 h-4 mr-3 text-ch-orange" /> Inspecionar Ativos
                                                            </DropdownMenuItem>
                                                            <DropdownMenuItem onClick={() => navigate(`/campanhas/${campaign.id}/editar`)} className="rounded-lg py-3 hover:bg-white/5 cursor-pointer">
                                                                <ListChecks className="w-4 h-4 mr-3 text-blue-400" /> Configurar Criativos
                                                            </DropdownMenuItem>
                                                            <DropdownMenuItem onClick={() => handleRunDiagnosis(campaign.id)} className="rounded-lg py-3 hover:bg-white/5 cursor-pointer">
                                                                <Sparkles className="w-4 h-4 mr-3 text-ch-orange" /> Diagnóstico IA
                                                            </DropdownMenuItem>
                                                            <div className="h-px bg-white/5 my-2" />
                                                            {campaign.status === 'active' ? (
                                                                <DropdownMenuItem className="rounded-lg py-3 text-rose-500 focus:text-rose-400 hover:bg-rose-500/5 cursor-pointer" onClick={async () => {
                                                                    await executeAction(campaign.id, 'pause');
                                                                    toast.success('Suspensão do motor de campanha executada');
                                                                    queryClient.invalidateQueries({ queryKey: ['campaigns'] });
                                                                }}>
                                                                    <Pause className="w-4 h-4 mr-3" /> Suspender Operação
                                                                </DropdownMenuItem>
                                                            ) : (
                                                                <DropdownMenuItem className="rounded-lg py-3 text-emerald-500 focus:text-emerald-400 hover:bg-emerald-500/5 cursor-pointer" onClick={async () => {
                                                                    await executeAction(campaign.id, 'activate');
                                                                    toast.success('Motor de campanha reativado');
                                                                    queryClient.invalidateQueries({ queryKey: ['campaigns'] });
                                                                }}>
                                                                    <Play className="w-4 h-4 mr-3" /> Reativar Operação
                                                                </DropdownMenuItem>
                                                            )}
                                                        </DropdownMenuContent>
                                                    </DropdownMenu>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    );
                                })}
                            </TableBody>
                        </Table>
                    </div>
                ) : (
                    <div className="py-40 text-center flex flex-col items-center glass-premium border-none">
                        <div className="w-24 h-24 bg-ch-orange/5 border border-ch-orange/10 rounded-[2.5rem] flex items-center justify-center mb-8">
                            <Megaphone className="w-10 h-10 text-ch-orange animate-pulse" />
                        </div>
                        <h2 className="text-2xl font-black text-ch-white uppercase tracking-tight mb-2">Vácuo de Operações</h2>
                        <p className="text-ch-text-muted max-w-sm mx-auto font-medium mb-10 leading-relaxed uppercase text-[10px] tracking-widest">
                            Nenhum ativo detectado sob as condições atuais de filtragem. Sincronize com o Meta para expandir.
                        </p>
                        <Button
                            variant="outline"
                            className="bg-ch-dark-gray/40 border-white/5 hover:bg-white/5 text-ch-orange font-black uppercase text-[11px] tracking-widest h-14 px-10 rounded-2xl transition-all"
                            onClick={() => { setSearch(''); setStatusFilter('all'); }}
                        >
                            Resetar Parâmetros Globais
                        </Button>
                    </div>
                )}

                {/* Ledger Navigation */}
                {!isLoading && totalPages > 1 && (
                    <div className="px-8 py-8 border-t border-white/5 flex items-center justify-between bg-white/[0.01]">
                        <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-wide">
                            Exibindo Lote Ativo {page * PAGE_SIZE + 1} — {Math.min((page + 1) * PAGE_SIZE, total)} / {total} TOTAL
                        </p>
                        <div className="flex items-center gap-4">
                            <Button
                                variant="outline"
                                size="icon"
                                onClick={() => setPage(p => Math.max(0, p - 1))}
                                disabled={page === 0}
                                className="h-12 w-12 bg-white/5 border-white/5 hover:bg-white/10 rounded-2xl transition-all disabled:opacity-20"
                            >
                                <ChevronLeft className="w-5 h-5" />
                            </Button>
                            <div className="flex items-center px-6 py-3 bg-white/5 rounded-2xl border border-white/5">
                                <span className="text-xs font-black text-ch-white uppercase">Bloco {page + 1} <span className="text-ch-text-dimmed mx-2 opacity-30">|</span> {totalPages}</span>
                            </div>
                            <Button
                                variant="outline"
                                size="icon"
                                onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                                disabled={page >= totalPages - 1}
                                className="h-12 w-12 bg-white/5 border-white/5 hover:bg-white/10 rounded-2xl transition-all disabled:opacity-20"
                            >
                                <ChevronRight className="w-5 h-5" />
                            </Button>
                        </div>
                    </div>
                )}
            </motion.div>

            <AiDiagnosisModal
                isOpen={isAiModalOpen}
                onClose={() => setIsAiModalOpen(false)}
                data={aiData}
                isLoading={isAiLoading}
                onReanalyze={() => selectedCampaignId && handleRunDiagnosis(selectedCampaignId)}
                title="Diagnóstico de Campanha"
            />
        </motion.div>
    );
}

